<script lang="ts">import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import PageHeader from '$lib/components/PageHeader.svelte';import AdminStatCard from '$lib/components/AdminStatCard.svelte';import AdminSection from '$lib/components/AdminSection.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminOverview, type AdminOverview} from '$lib/api';let data:AdminOverview|null=null;let loading=false;let error='';const load=async()=>{loading=true;error='';try{data=await fetchAdminOverview();}catch(e:any){error=e.message||'Erreur';}finally{loading=false;}};onMount(load);</script>
<AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<PageHeader title="Admin Overview" subtitle="Cockpit SaaS"/><button on:click={load}>Refresh</button>{#if loading}<p>Chargement…</p>{/if}{#if error}<p>{error}</p>{/if}{#if data}<AdminSection title="Utilisateurs"><div class="g"><AdminStatCard label="Total" value={String(data?.users?.total ?? 0)}/><AdminStatCard label="Verified" value={String(data?.users?.verified ?? 0)}/><AdminStatCard label="Admins" value={String(data?.users?.admins ?? 0)}/><AdminStatCard label="Reports pending" value={String(data?.reports?.pending ?? 0)}/></div></AdminSection>{/if}{/if}</AppShell>
